resource "kubernetes_role_v1" "restarter" {
  metadata {
    name      = local.restart_name
    namespace = local.kubernetes_namespace
    labels = {
      app = local.restart_name
    }
  }

  rule {
    api_groups     = ["apps"]
    resources      = ["deployments"]
    resource_names = local.restart_deployments
    verbs          = ["get", "patch"]
  }
}

resource "kubernetes_role_binding_v1" "restarter" {
  metadata {
    name      = local.restart_name
    namespace = local.kubernetes_namespace
    labels = {
      app = local.restart_name
    }
  }

  role_ref {
    api_group = "rbac.authorization.k8s.io"
    kind      = "Role"
    name      = kubernetes_role_v1.restarter.metadata[0].name
  }

  subject {
    kind      = "ServiceAccount"
    name      = kubernetes_service_account_v1.restarter.metadata[0].name
    namespace = local.kubernetes_namespace
  }
}

resource "kubernetes_cron_job_v1" "restarter" {
  metadata {
    name      = local.restart_name
    namespace = local.kubernetes_namespace
    labels = {
      app = local.restart_name
    }
  }

  spec {
    schedule                      = local.restart_schedule
    concurrency_policy            = "Forbid"
    successful_jobs_history_limit = 1
    failed_jobs_history_limit     = 3
    starting_deadline_seconds     = 300

    job_template {
      metadata {
        labels = {
          app = local.restart_name
        }
      }

      spec {
        backoff_limit              = 2
        active_deadline_seconds    = 600
        ttl_seconds_after_finished = 3600

        template {
          metadata {
            labels = {
              app = local.restart_name
            }
          }

          spec {
            service_account_name = kubernetes_service_account_v1.restarter.metadata[0].name
